    const p = this.player;
    const RADIUS = 155 * (1 + 0.12 * this._cardLvl('cyber_heavy_chains_mastery')), DURATION = 7;
    const a = Math.max(0, Math.min(oc.t / 0.3, (DURATION - oc.t) / 0.5, 1));   // fade in/out

