      ctx.beginPath(); ctx.moveTo(d.x, topY); ctx.lineTo(d.x, bottomY); ctx.stroke();
      ctx.restore();
      ctx.globalAlpha = 0.9 * fade;
      ctx.strokeStyle = '#ff5a14'; ctx.lineWidth = 9;
      ctx.beginPath(); ctx.moveTo(d.x, topY); ctx.lineTo(d.x, bottomY); ctx.stroke();
      ctx.strokeStyle = '#ffd27a'; ctx.lineWidth = 4;
      ctx.beginPath(); ctx.moveTo(d.x, topY); ctx.lineTo(d.x, bottomY); ctx.stroke();
