            ctx.translate(fx3, fy3);
            ctx.rotate(Math.sin(f.t * 2.4 + i2 * 2) * 0.7);
            ctx.globalAlpha = (1 - after) * 0.85;
            ctx.fillStyle = i2 % 2 ? '#e8f2ff' : '#ffffff';
